export const DEFAULT_CITY_KEY = "Toronto,Ontario,Canada"

export function cityKey(c: CityRecord): string {
  return `${c.name},${c.admin},${c.country}`
}

const BY_KEY = new Map<string, CityRecord>(WORLD_CITIES.map(c => [cityKey(c), c]))

export function findCityByKey(key: string): CityRecord | undefined {
  return BY_KEY.get(key)
}

/** DST-aware UTC offset in hours for the given IANA timezone at the given date. */
export function getTzOffsetHours(tz: string, date: Date): number {
  const dtf = new Intl.DateTimeFormat("en-US", {
    timeZone: tz,
    year: "numeric", month: "2-digit", day: "2-digit",
    hour: "2-digit", minute: "2-digit", second: "2-digit",
    hour12: false,
  })
  const parts: Record<string, string> = {}
  for (const p of dtf.formatToParts(date)) parts[p.type] = p.value
  const asUtc = Date.UTC(
    Number(parts.year),
    Number(parts.month) - 1,
    Number(parts.day),
    Number(parts.hour) === 24 ? 0 : Number(parts.hour),
    Number(parts.minute),
    Number(parts.second),
  )
  return (asUtc - date.getTime()) / 3_600_000
}
